refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/circbw.tif"));
image = imresize(image, [64 64]);
theta = 0:10:170;
[projection, radius] = imradon(image, theta);
reconstructed = imiradon(projection, theta, 64);
subplot(1, 3, 1);
imshow(image);
subplot(1, 3, 2);
imshow(projection, hot(64));
subplot(1, 3, 3);
imshow(reconstructed);
